public class HDG_ExcelUploadUIBuilder extends SysOperationAutomaticUIBuilder
{
    private FileUpload fileUpload;
    private const str uploadControlName = 'ExcelUpload';

}

Method.Source:
/// <summary>
/// 허용할 파일 확장자를 반환합니다.
/// </summary>
protected str getAcceptedFileTypes()
{
    return ".xlsx";
}

public void postBuild()
{
    super();

    FormBuildDesign formDesign = this.dialog().formBuildDesign();
    FormBuildGroupControl contentGroup = formDesign.control('ParametersGroup');

    // 파일 업로드 컨트롤 추가
    FileUploadBuild fileUploadBuild = contentGroup.addControlEx(classStr(FileUpload), uploadControlName);
    fileUploadBuild.style(FileUploadStyle::MinimalWithFilename);
    fileUploadBuild.baseFileUploadStrategyClassName(classStr(FileUploadTemporaryStorageStrategy));
    fileUploadBuild.fileTypesAccepted(this.getAcceptedFileTypes());
}

/// <summary>
/// 사용자가 [확인] 버튼을 누를 때 호출됩니다.
/// </summary>
public void getFromDialog()
{
    super();

    FileUploadTemporaryStorageResult result = fileUpload.getFileUploadResult();

    if (result && result.getUploadStatus())
    {
        HDG_ExcelUploadContract contract = this.dataContractObject() as HDG_ExcelUploadContract;
        contract.parmFileUrl(result.getDownloadUrl());
    }
}
